class Solution:
    def sumDigitDifferences(self, nums: List[int]) -> int:
        n = len(nums)
        if n < 2:
            return 0

        # Convert each number to a string to easily access digits
        str_nums = [str(num) for num in nums]
        length = len(str_nums[0])

        total = 0

        # Iterate over each digit position
        for i in range(length):
            # Count the frequency of each digit at position i
            freq = {}
            for num in str_nums:
                digit = num[i]
                freq[digit] = freq.get(digit, 0) + 1

            # Calculate the number of pairs with different digits
            # For each digit, the number of pairs with other digits is count * (n - count)
            for count in freq.values():
                total += count * (n - count)

        return total // 2  # Each pair is counted twice
